import { toList, map, singleton, collect, delay, toArray } from "./fable_modules/fable-library.3.7.20/Seq.js";
import { equals } from "./fable_modules/fable-library.3.7.20/Util.js";
import { Node$, Primitive, Selector, ReferenceKind } from "./doc/doc.fs.js";
import { OrdList_ofList } from "./utils/ordlist.fs.js";

export function selToJson(_arg) {
    switch (_arg.tag) {
        case 1: {
            const n = _arg.fields[0];
            return "#" + n;
        }
        case 0: {
            return "*";
        }
        case 3: {
            return "..";
        }
        default: {
            const f = _arg.fields[0];
            return f;
        }
    }
}

export function nodeToJson(_arg) {
    if (_arg.tag === 0) {
        const nds = _arg.fields[1];
        const tag = _arg.fields[0];
        return {
            kind: "record",
            tag: tag,
            nodes: toArray(delay(() => collect((matchValue) => {
                const nd = matchValue[1];
                const n_1 = matchValue[0];
                return singleton([n_1, nodeToJson(nd)]);
            }, nds))),
        };
    }
    else if (_arg.tag === 1) {
        const nds_1 = _arg.fields[1];
        const tag_1 = _arg.fields[0];
        return {
            kind: "list",
            tag: tag_1,
            nodes: toArray(delay(() => collect((matchValue_1) => {
                const nd_1 = matchValue_1[1];
                const n_2 = matchValue_1[0];
                return singleton([n_2, nodeToJson(nd_1)]);
            }, nds_1))),
        };
    }
    else if (_arg.tag === 3) {
        const kind = _arg.fields[0];
        const sels = _arg.fields[1];
        return {
            kind: "reference",
            refkind: equals(kind, new ReferenceKind(0)) ? "absolute" : "relative",
            selectors: toArray(delay(() => map(selToJson, sels))),
        };
    }
    else if (_arg.fields[0].tag === 0) {
        const n = _arg.fields[0].fields[0];
        return n;
    }
    else {
        const s = _arg.fields[0].fields[0];
        return s;
    }
}

export function selFromJson(o) {
    if ((typeof o) === "number") {
        return new Selector(1, o);
    }
    else if ((typeof o) === "string") {
        const s = o;
        if (s === "*") {
            return new Selector(0);
        }
        else if (s === "..") {
            return new Selector(3);
        }
        else if (s.indexOf("#") === 0) {
            return new Selector(1, s.slice(1, s.length));
        }
        else {
            return new Selector(2, s);
        }
    }
    else {
        throw (new Error(`selFromJson - unexpected object ${o}`));
    }
}

export function nodeFromJson(o) {
    if ((typeof o) === "string") {
        return new Node$(2, new Primitive(1, o));
    }
    else if ((typeof o) === "number") {
        return new Node$(2, new Primitive(0, o));
    }
    else if ((o["kind"]) === "list") {
        return new Node$(1, o["tag"], OrdList_ofList(toList(delay(() => map((o_1) => [o_1[0], nodeFromJson(o_1[1])], o["nodes"])))));
    }
    else if ((o["kind"]) === "record") {
        return new Node$(0, o["tag"], OrdList_ofList(toList(delay(() => map((o_2) => [o_2[0], nodeFromJson(o_2[1])], o["nodes"])))));
    }
    else if ((o["kind"]) === "reference") {
        return new Node$(3, ((o["refkind"]) === "relative") ? (new ReferenceKind(1)) : (new ReferenceKind(0)), toList(delay(() => map(selFromJson, o["selectors"]))));
    }
    else {
        throw (new Error(`nodeFromJson - unexpected object: ${o}`));
    }
}

export function nodesToJson(nds) {
    return toArray(delay(() => map(nodeToJson, nds)));
}

export function nodesFromJson(obj) {
    return toList(delay(() => map(nodeFromJson, obj)));
}

export function nodesToJsonString(nds) {
    return JSON.stringify(nodesToJson(nds));
}

export function nodesFromJsonString(s) {
    return nodesFromJson(JSON.parse(s));
}

